"""
MKT Original Commentary — Genesis chapters 1–3
Run: python3 scripts/zc-original-genesis-1-3.py

Source data used:
- data/interlinear/genesis.json
- data/translation/glossary-hebrew.json (semantic ranges)
- data/translation/notes/genesis.json (per-verse token data)
- data/translation/draft/mediating/genesis.json (MKT text)

Key decisions:
- אֱלֹהִים (ʾĕlōhîm): grammatically plural but takes singular verb throughout ch 1 —
  not translated "gods" because the verb agreement requires singular referent; the plural
  likely carries a plural-of-majesty or fullness-of-deity sense
- בָּרָא (bārāʾ) vs. עָשָׂה (ʿāśâ): bārāʾ (create, always with God as subject in OT)
  reserved for specific acts; ʿāśâ (make, do) used more broadly — distinction tracked
- רוּחַ (rûaḥ) at 1:2: rendered "Spirit of God" rather than "wind of God" — rûaḥ is
  semantically ambiguous (wind, breath, spirit); context + mĕraḥepet (hovering/brooding)
  points toward personal divine activity rather than meteorological force
- תֹהוּ וָבֹהוּ (tōhû wābōhû): alliterative pair meaning formless-and-empty; not chaos
  in the Greek sense but unformed, uninhabited potential — no claim about pre-creation state
- יוֹם (yôm) with ordinal: "the first day" etc. — yôm can mean 24-hour period, daylight
  hours, or an indefinite era; the evening-and-morning sequence is noted but its interpretive
  weight is contested; the commentary notes what the Hebrew does, not which view is correct
- נֶפֶשׁ (nepeš) at 2:7: the whole person animated — not an immaterial soul inserted into
  a body but the unified living being; rendered "living creature/person"
- זֶרַע (zeraʿ) at 3:15: collective singular — can refer to corporate offspring or a
  specific descendant; the grammar does not resolve the Christological debate but does
  allow a singular reading
- שׁוּף (šûp) at 3:15: same verb for both "crush" and "strike" — the enmity is mutual
  but asymmetric in outcome
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "1": {
    "1": '<p><strong>בְּרֵאשִׁית</strong> (<em>bĕrēʾšît</em>) — "In the beginning." The word is in construct state (no definite article in Hebrew), making the phrase technically "in a beginning" or "in the beginning of." This ambiguity is intentional: the phrase functions as an absolute temporal marker, not a description of a defined starting point. It introduces the entire creative act as the founding event.</p><p><strong>בָּרָא</strong> (<em>bārāʾ</em>) — the verb used exclusively with God as subject throughout the OT. Unlike <em>ʿāśâ</em> (make/do) or <em>yāṣar</em> (form/shape), <em>bārāʾ</em> carries no object requiring prior material — though the text does not explicitly assert <em>ex nihilo</em>; that inference comes from the total picture. The Qal perfect ("he created") presents the act as a completed whole from the narrator\'s standpoint.</p><p><strong>אֱלֹהִים</strong> (<em>ʾĕlōhîm</em>) — the plural form takes the singular verb <em>bārāʾ</em> throughout Genesis 1; this grammatical mismatch is consistent and deliberate. The plural likely carries a fullness-of-deity or plural-of-majesty sense rather than a reference to multiple beings, though it opens space for later Trinitarian reading.</p>',
    "2": '<p><strong>תֹהוּ וָבֹהוּ</strong> (<em>tōhû wābōhû</em>) — an alliterative, rhyming word-pair meaning "formless and empty" or "unformed and uninhabited." Neither word denotes chaos or destruction in itself; together they describe a state prior to ordered, inhabited creation. The phrase recurs in Jer 4:23 applied to desolated land — showing the pair describes the undoing of ordered creation, not primordial evil.</p><p><strong>רוּחַ אֱלֹהִים</strong> (<em>rûaḥ ʾĕlōhîm</em>) — rûaḥ spans wind, breath, and spirit; the context tips toward the personal divine agent because of <em>mĕraḥepet</em> (hovering/brooding), a Piel participle from a root used of a bird caring for her young (Deut 32:11). Wind does not hover in this deliberate, nurturing sense; the personal Spirit who will animate creation is already present over the unformed deep.</p><p><strong>תְּהוֹם</strong> (<em>tĕhôm</em>) — "the deep," cognate with Babylonian <em>Tiamat</em>. Unlike Babylonian cosmogony, the deep here is not a monster to be slain but a neutral condition over which God acts freely. The absence of a creation-combat myth is itself a theological statement.</p>',
    "3": '<p><strong>וַיֹּאמֶר אֱלֹהִים</strong> — the waw-consecutive imperfect (<em>wayyiqtol</em>) inaugurates the creation narrative\'s sequence. Hebrew narrative past tense uses this form throughout ch 1: each divine speech and act is rendered sequentially by waw + imperfect, not by simple perfects. The effect is a cascade of completed actions in real time.</p><p><strong>יְהִי אוֹר</strong> (<em>yĕhî ʾôr</em>) — the jussive "let there be light." Light is created before the luminaries of day 4 — the light of day 1 is not solar light. The separation of the light-source from the light-bearing objects prevents any identification of אוֹר with the sun, important given Babylonian sun-worship. The Hebrew makes no further comment; the gap is theologically loaded.</p>',
    "4": '<p><strong>כִּי-טוֹב</strong> (<em>kî-ṭôb</em>) — "that it was good." The <em>kî</em> introduces a direct object clause: God saw that. <em>ṭôb</em> is an aesthetic-moral-functional term — good in the sense of fitting, right, beautiful, and working as intended. Each evaluation unit closes with this phrase; the cumulative effect is a God who evaluates rather than merely produces.</p><p><strong>וַיַּבְדֵּל</strong> (<em>wayyabdēl</em>) — "and he separated." The verb <em>bādal</em> (to divide, distinguish) is used in Levitical purity law for holy-versus-common distinctions. God\'s creative work is structuring by distinction; the same verb will describe the Levites\' separating role (Num 16:9) and Israel\'s call to distinguish between clean and unclean.</p>',
    "5": '<p><strong>וַיִּקְרָא</strong> (<em>wayyiqrāʾ</em>) — "and he called/named." In the ANE, naming is an act of authority and definition — to name is to establish the nature and role of a thing. God names the light "Day" and darkness "Night"; Adam will later name the animals (2:19-20), exercising derivative dominion through the same act.</p><p><strong>יוֹם אֶחָד</strong> (<em>yôm ʾeḥāḏ</em>) — "one day" (cardinal, not "first day" as in the ordinal forms used for days 2–6). The distinction may signal that the first day stands apart as the foundation; alternatively, the cardinal signals the day is complete in itself. The evening-morning sequence (evening first) follows the Hebrew reckoning of a day starting at sundown.</p>',
    "6": '<p><strong>רָקִיעַ</strong> (<em>rāqîaʿ</em>) — from <em>rāqaʿ</em> (to beat out, spread thin — used of hammering metal into sheets, Exod 39:3). The term describes a stretched-out expanse rather than a solid vault; the cognate Akkadian concept does imply a firmament, but the Hebrew verbal root emphasizes extension and spreading rather than rigid solidity. The MKT renders "expanse" rather than "firmament" to avoid reading in a cosmological theory the text does not require.</p>',
    "7": '<p>The distinction between <em>bārāʾ</em> (create, v. 1, 21, 27) and <em>ʿāśâ</em> (make, v. 7, 16, 25) is not absolute — both are used of God\'s creative acts — but <em>bārāʾ</em> appears at key junctures (creation itself, sea creatures and birds, humanity) while <em>ʿāśâ</em> covers the making of the expanse, the luminaries, and land animals. The pattern may signal that <em>bārāʾ</em> marks the truly novel; <em>ʿāśâ</em> covers formation and arrangement of existing material.</p>',
    "8": '<p>The repeated <em>wayyĕhî-ʿereb wayyĕhî-bōqer</em> ("and there was evening and there was morning") functions as a boundary marker closing each creation day. The waw-consecutive forms (<em>wayyĕhî</em>) keep the narrative moving — these are not isolated static descriptions but links in a temporal chain. The formula\'s regularity creates an architectural rhythm that the seventh day (2:1-3) will deliberately break.</p>',
    "9": '<p><strong>יִקָּווּ</strong> (<em>yiqqāwû</em>) — Niphal imperfect of <em>qāwāh</em> (to collect, wait). The waters gather themselves by divine command — the passive (Niphal) voice emphasizes divine causation without direct physical intervention; God speaks and reality conforms.</p><p><strong>תֵּרָאֶה</strong> (<em>tērāʾeh</em>) — Niphal imperfect, "let the dry ground appear" — again the passive of appearance by command. The land does not so much emerge as become visible as the waters comply. The same verb will describe theophany: the LORD appears (<em>nîrāʾ</em>) to the patriarchs.</p>',
    "10": '<p>God names the dry ground <strong>אֶרֶץ</strong> (<em>ʾereṣ</em>, "land/earth") and the gathered waters <strong>יַמִּים</strong> (<em>yammîm</em>, "seas"). The naming authority exercised in v. 5 continues. The verb <em>wayyiqrāʾ</em> is the same throughout — naming as the royal act of defining and governing what one names.</p>',
    "11": '<p><strong>לְמִינֵהוּ</strong> (<em>lĕmînēhû</em>) — "according to its kind." The phrase appears ten times in ch 1 and establishes the boundaries of reproducible kinds. The Hebrew <em>mîn</em> does not map exactly onto any modern biological category; it describes reproducibility within a kind. The phrase is not a statement about species boundaries but about the orderliness of creation — vegetation reproduces what it is.</p>',
    "12": '<p>The land "brought forth" (<em>waṯṣēʾ hāʾāreṣ</em>) in response to God\'s word — the ground is an agent executing the divine command, not merely a passive substrate. This mediated creation (God speaks → earth produces) is the pattern for the sea creatures (v. 20), land animals (v. 24), and eventually humanity (2:7, where God acts more directly). Each creative domain has its own mode of response.</p>',
    "13": '<p>The evening-morning formula closes the third day. Note that days 1-3 (separation: light/dark, waters/waters, water/land) are structurally paired with days 4-6 (filling: luminaries, birds/fish, land animals/humanity). Day 7 stands outside the pair. This literary architecture is a feature of the Hebrew, not translatable; it signals the text\'s compositional intentionality.</p>',
    "14": '<p><strong>אֹתֹת וּמוֹעֲדִים</strong> (<em>ʾōtōt ûmôʿăḏîm</em>) — "signs and appointed times." <em>Môʿēd</em> (pl. <em>môʿăḏîm</em>) is the word used for Israel\'s appointed feasts (Lev 23:2-4) — the sacred calendar. The luminaries are set in the sky to govern the calendar, including the religious calendar; the creation of timekeeping is intrinsically tied to the ordering of worship. This verse is the theological basis for Sabbath and festival reckoning from the creation order.</p>',
    "15": '<p>The purpose clause — <em>lĕhāʾîr ʿal-hāʾāreṣ</em> ("to give light on the earth") — specifies function over essence. The text is not interested in the physics of luminaries but in their teleological role as servants of God\'s ordered creation. They are made (<em>ʿāśâ</em>) and placed (<em>nātan</em>) in service of the earth below.</p>',
    "16": '<p><strong>שְׁנֵי הַמְּאֹרֹת הַגְּדֹלִים</strong> (<em>šĕnê hammĕʾōrōt haggĕḏōlîm</em>) — "the two great lights." Notably, the sun and moon are not named in the Hebrew text. The surrounding cultures had names — Shamash (sun), Sin (moon) — that carried divine status. By calling them only "the greater light" and "the lesser light," the text demotes them from deities to instruments. The stars are added almost as an afterthought ("and the stars also"), further reducing their cultic significance.</p>',
    "17": '<p>God "set them" (<em>wayyittēn</em>) in the expanse — the verb <em>nātan</em> (give, set, place) is used here as a functional placement. The luminaries are placed in a location for a purpose; they have no independent will or divine status. The same word describes giving gifts, placing objects, and assigning roles — here the luminaries are assigned servants, not worshipped lords.</p>',
    "18": '<p>The evaluation <em>kî-ṭôb</em> follows the luminaries\' commission. Three functions are named: governing day and night, separating light from darkness. The threefold statement of purpose before the evaluation recalls the pattern of each creation unit — the goodness is tied to the fitness of the thing for its appointed role.</p>',
    "19": '<p>The evening-morning formula (fourth day). The structural pair with day 1 (light/dark separation) is now complete: day 1 created the condition, day 4 created the governors of that condition. The Hebrew architecture is clearer than any translation: days 1-3 create realms; days 4-6 fill them in corresponding order.</p>',
    "20": '<p><strong>יִשְׁרְצוּ</strong> (<em>yišrĕṣû</em>) — "let them swarm/teem." The verb <em>šāraṣ</em> denotes swarming, teeming life — used of small creatures in masses (insects, fish, frogs; cf. Exod 8:3; Lev 11:29). The same root gives <em>šereṣ</em> (swarming things), a major category of Levitical impurity. The use of the verb here is simply about abundance; the later purity connotations are applied differently.</p><p><strong>עוֹף</strong> (<em>ʿôp</em>) — "flying creatures," not strictly "birds." The root <em>ʿûp</em> means to fly; the category includes all that flies and is broader than modern "birds." The MKT\'s "birds" approximates; the Hebrew does not exclude flying insects.</p>',
    "21": '<p><strong>וַיִּבְרָא</strong> — <em>bārāʾ</em> reappears here (day 5) after being absent since v. 1. The reuse marks sea creatures and birds as a category requiring a special creative act — not just forming or making but <em>bārāʾ</em>. The pattern will repeat at v. 27 for humanity. These three <em>bārāʾ</em> uses may mark the three most significant creative boundaries.</p><p><strong>הַתַּנִּינִם הַגְּדֹלִים</strong> (<em>hattannînim haggĕḏōlîm</em>) — "the great sea creatures." The same word (<em>tannîn</em>) is used elsewhere for the sea-monster Leviathan (Ps 74:13; Isa 27:1). Here it is demythologized: the great sea creatures are made things, not divine adversaries. They are <em>created</em> by God and evaluated as <em>ṭôb</em>.</p>',
    "22": '<p><strong>וַיְבָרֶךְ אֹתָם אֱלֹהִים</strong> — the first divine blessing in Genesis. The blessing formula (<em>bārak</em>) confers fruitfulness and multiplication. The same blessing will be given to humanity (1:28) and later to Noah (9:1). The blessing is functional — it enables and capacitates the creatures to fill their domains. The sea creatures and birds are blessed before any command is given to them beyond reproduction.</p>',
    "23": '<p>Fifth day formula closes. The architecture of the creation narrative requires that sea/sky (day 5) correspond to the separation of waters/sky (day 2). The filling of the sea and sky is now complete; day 6 will fill the land corresponding to day 3\'s land/sea distinction.</p>',
    "24": '<p><strong>נֶפֶשׁ חַיָּה</strong> (<em>nepeš ḥayyâ</em>) — "living creatures/souls." The same phrase will describe the human being at 2:7. <em>Nepeš</em> is the animated, living being — not an immaterial soul but the whole creature in its vitality. Land animals and humanity share this description; the distinction comes in how they receive it (ground-production for animals; divine formation and breath for humanity).</p>',
    "25": '<p>The <em>kî-ṭôb</em> evaluation for land animals. All three categories — <em>ḥayyat hāʾāreṣ</em> (wild beasts), <em>bĕhēmāh</em> (livestock), and <em>remeś</em> (creeping things) — are evaluated good individually in the Hebrew. The MKT\'s "livestock" for <em>bĕhēmāh</em> captures the domesticated-animal sense (cattle, sheep, donkeys).</p>',
    "26": '<p><strong>נַעֲשֶׂה</strong> (<em>naʿăśeh</em>) — cohortative first-person plural: "let us make." This is the only first-person plural in God\'s speech in ch 1. Three explanations in the tradition: (1) plural of majesty; (2) God addressing the heavenly court (the "us" = divine council as in Job 1-2, 1 Kgs 22:19-22); (3) proleptic Trinitarian. The Hebrew does not settle this; the plural is factual and unexplained. The verb then shifts to singular: "and God created" (v. 27 uses <em>bārāʾ</em> with singular subject).</p><p><strong>בְּצַלְמֵנוּ כִּדְמוּתֵנוּ</strong> (<em>bĕṣalmēnû kiḏmûtēnû</em>) — "in our image, according to our likeness." Two distinct words: <em>ṣelem</em> (image, also used of idols and statues — a concrete representation) and <em>dĕmût</em> (likeness, resemblance — an abstract comparison). Together they assert full representative correspondence without complete identification. Humanity is the <em>ṣelem</em> of God — the ANE cognate use is of a king\'s statue placed in territories he could not personally visit; the statue carried his authority and presence.</p><p><strong>וְיִרְדּוּ</strong> (<em>wĕyirdû</em>) — "that they may rule." <em>Rādāh</em> (to tread, rule, have dominion) is the vocabulary of royal authority. The <em>ṣelem</em> language (king\'s representative statue) and <em>rādāh</em> (royal rule) together place humanity in the role of God\'s viceregents over creation — the image-bearing is inseparable from the dominion-bearing.</p>',
    "27": '<p><strong>וַיִּבְרָא אֱלֹהִים אֶת-הָאָדָם בְּצַלְמוֹ</strong> — <em>bārāʾ</em> appears three times in this verse: "God created mankind... in his image he created him; male and female he created them." The threefold repetition is poetic (this is one of the few poetic couplets/triplets in the creation narrative) and emphatic. The third <em>bārāʾ</em> expands from the individual to the pair: <em>zākār ûnĕqēbāh</em> (male and female), both are the <em>ṣelem</em> of God, both are created (<em>bārāʾ</em>) — not derived sequentially as in ch 2 but co-created as image-bearers together.</p><p><strong>אָדָם</strong> (<em>ʾāḏām</em>) — in ch 1 this is the generic term for humankind (collective), not the proper name Adam. The semantic range covers: mankind collectively, a human being, and the proper name Adam (used in ch 5). The MKT renders "mankind" in ch 1 to preserve the collective sense; the shift to the proper name occurs at 2:20 and especially 3:17.</p>',
    "28": '<p><strong>וַיְבָרֶךְ אֹתָם</strong> — the blessing precedes the mandate: God blesses before commanding. The fertility command (<em>pĕrû ûrĕbû</em>, be fruitful and multiply) is not a law but the activation of a capacity already given in the blessing. The same formula appears at Noah\'s re-commissioning (9:1, 7) and the Abrahamic promises — the creation mandate is renewed after each catastrophic disruption.</p><p><strong>כִּבְשֻׁהָ</strong> (<em>kibbĕšûhā</em>) — "subdue it." <em>Kābaš</em> is a strong term (tread down, subdue, bring into subjection — used of subduing enemies, Num 32:22, 29; Josh 18:1). Its use for humanity\'s relationship to the earth is intentionally robust — the mandate is not gentle management but active, purposeful ordering. This is royal-administrative language, not merely gardening.</p>',
    "29": '<p><strong>זֹרֵעַ זֶרַע</strong> (<em>zōrēaʿ zeraʿ</em>) — "seed-bearing," a participial phrase modifying plants. The preoccupation with seed-bearing points forward to the seed as the mechanism of continuity — the same word <em>zeraʿ</em> will carry the promise of Gen 3:15. In ch 1 it is simply agricultural; its recurrence in 3:15, 12:7, 13:15, 15:3-5, 22:17-18 shows the seed motif gathering theological weight.</p>',
    "30": '<p>The extension of plant-food to all living creatures (<em>nepeš ḥayyâ</em>) in the original creation establishes a pre-Fall order without predation. The absence of meat-eating in the original mandate (reversed at 9:3 after the Flood) is a textual fact that the Hebrew presents without explicit comment. The <em>kî kēn</em> ("and it was so") formula closes with simple compliance.</p>',
    "31": '<p><strong>מְאֹד</strong> (<em>mĕʾōḏ</em>) — "very." The single adverb elevates the cumulative evaluation beyond each day\'s <em>ṭôb</em>: all that he had made is not just good but emphatically, thoroughly good. This is the only use of <em>mĕʾōḏ</em> with <em>ṭôb</em> in the creation account — the final assessment is heightened over all partial ones. The sixth day closes the pairing with day 3 and completes the filling of creation\'s realms.</p>'
  },
  "2": {
    "1": '<p><strong>וַיְכֻלּוּ</strong> (<em>wayĕkullû</em>) — Pual imperfect of <em>kālāh</em> (to be complete, finished, brought to an end). The passive voice: the heavens and earth were completed — they brought themselves to completion under God\'s creative word. The same root <em>kālāh</em> will describe the completion of the tabernacle (Exod 40:33) and Solomon\'s temple (1 Kgs 6:9; 7:51) — a structural echo suggesting that creation itself is a cosmic sanctuary.</p><p><strong>צְבָאָם</strong> (<em>ṣĕbāʾām</em>) — "their host/array." <em>Ṣābāʾ</em> (army, host) is used of the stars (Deut 4:19; Isa 45:12) and of the angels (1 Kgs 22:19). The term frames creation as an ordered host under the supreme commander — God as the LORD of Hosts (<em>YHWH ṣĕbāʾôt</em>) is already implicit in the creational completion.</p>',
    "2": '<p><strong>וַיִּשְׁבֹּת</strong> (<em>wayyišbōt</em>) — "and he rested/ceased." The root is <em>šābat</em>, from which "Sabbath" (<em>šabbāt</em>) derives. The word means to stop, cease — not to recover from fatigue (Exod 31:17 explicitly says God did not become weary). God\'s rest is the completion-rest of a creator whose work is finished, not the rest of a laborer. The Sabbath commandment (Exod 20:11; Deut 5:14-15) points back to this verse as its foundation — Israel rests because God rested.</p><p><strong>מְלַאכְתּוֹ</strong> (<em>mĕlaʾktô</em>) — "his work." The same word is used of the skilled craftwork of the tabernacle artisans (Exod 35-36). The creation of the cosmos and the construction of the sanctuary are described in parallel vocabulary — the priestly authors of ch 1-2 may have intentionally structured the comparison.</p>',
    "3": '<p><strong>וַיְקַדֵּשׁ אֹתוֹ</strong> (<em>wayĕqaddēš ʾōtô</em>) — "and he sanctified/made it holy." <em>Qādaš</em> (Piel) means to set apart as holy, consecrate. The seventh day is the first holy thing in Genesis — before the tabernacle, before Sinai, God establishes holiness in time. The Sabbath is a sanctuary in time rather than space, and its sanctification precedes all human worship structures.</p><p>The seventh day notably lacks the evening-morning closing formula used for days 1-6. The rabbis observed this absence and interpreted the seventh day as having no end — open-ended, still continuing. Hebrews 4:9-10 builds on this: there remains a Sabbath-rest for the people of God.</p>',
    "4": '<p><strong>אֵלֶּה תוֹלְדוֹת</strong> (<em>ʾēlleh tôlĕḏôt</em>) — "these are the generations/account of." The formula <em>tôlĕḏôt</em> (from <em>yālad</em>, to bear/beget) recurs ten times in Genesis as a structural marker (2:4; 5:1; 6:9; 10:1; 11:10; 11:27; 25:12; 25:19; 36:1; 37:2). It introduces either a genealogy or a narrative account of what something or someone generated/produced. Here it looks backward: the account of how heavens and earth came to be.</p><p><strong>יְהוָה אֱלֹהִים</strong> (<em>YHWH ʾĕlōhîm</em>) — the divine name <em>YHWH</em> (the LORD, the personal covenantal name) first appears at 2:4. From here through ch 3, the compound "the LORD God" (<em>YHWH ʾĕlōhîm</em>) is used consistently. The shift from <em>ʾĕlōhîm</em> alone (ch 1) to the compound name (ch 2-3) has long been noted — it introduces the personal, relational, covenant-making God who enters into direct relationship with humanity.</p>',
    "5": '<p>The verse uses Hebrew circumstantial construction to set the scene before the narrative: "when no shrub... had yet sprung up — for the LORD God had not sent rain... and no man was there to work the ground." This pluperfect-style background clause (the Qal perfect with waw is often pluperfect in context) establishes that ch 2:4ff. is not a sequential continuation of ch 1\'s day 6 but a close-up on the forming of man before vegetation was established. The agricultural focus (<em>ʿāḇad hāʾăḏāmāh</em>, work the ground) is deliberate: the ground needs a worker, and God provides one.</p>',
    "6": '<p><strong>אֵד</strong> (<em>ʾēḏ</em>) — "mist" or "spring/stream." The term is rare (only here and Job 36:27); its precise meaning is contested. Cognate Akkadian <em>edu</em> means underground water/flood. Most modern scholars favor "springs" or "underground water" rising to water the surface — setting the agricultural scene before rain. The MKT\'s "streams" reflects this.</p>',
    "7": '<p><strong>וַיִּיצֶר יְהוָה אֱלֹהִים אֶת-הָאָדָם עָפָר מִן-הָאֲדָמָה</strong> — "and the LORD God formed (<em>yāṣar</em>) the man, dust from the ground." <em>Yāṣar</em> is the potter\'s verb (Jer 18:2-6; Isa 29:16; 45:9) — shaping by hand from material. The contrast with <em>bārāʾ</em> (ch 1) is significant: here humanity is formed from pre-existing material (<em>ʿāpār</em>, dust/topsoil) by the direct hands-on activity of God as craftsman. The connection between <em>ʾāḏām</em> (man) and <em>ʾăḏāmāh</em> (ground) is an untranslatable Hebrew wordplay: the man is humus from humus.</p><p><strong>נְשָׁמַת חַיִּים</strong> (<em>nišmat ḥayyîm</em>) — "breath of life." <em>Nĕšāmāh</em> is divine breath — not merely biological respiration but the animating force proceeding from God\'s own breath. The same word appears in Job 33:4 ("the breath of the Almighty gives me life") and Isa 42:5. Unlike the animals who received their <em>nepeš ḥayyâ</em> through the earth\'s production (1:24), the human receives life by direct divine inbreathing — face to face, mouth to nostril.</p><p><strong>לְנֶפֶשׁ חַיָּה</strong> (<em>lĕnepeš ḥayyâ</em>) — "into a living creature/soul." <em>Nepeš</em> is the whole animated person — not an immaterial soul housed in a body, but the total human being in its vitality. The same phrase is used of animals (1:24; 2:19). Humanity does not have a <em>nepeš</em>; humanity <em>is</em> a <em>nepeš</em>. The distinct feature here is the mode of animation: divine breath, not the earth\'s own generative capacity.</p>',
    "8": '<p><strong>גַּן-בְּעֵדֶן מִקֶּדֶם</strong> (<em>gan-bĕʿēḏen miqqeḏem</em>) — "a garden in Eden, in the east." <em>ʿĒḏen</em> may derive from the Sumerian/Akkadian <em>edinu</em> (steppe, plain) or from the Hebrew <em>ʿēḏen</em> (pleasure, luxury — Ps 36:8). The geographic "east" places Eden in the mythological/primordial east — the direction of sunrise and of origins. The garden is a subset within Eden: God planted a garden <em>in</em> Eden, not identified with all of Eden.</p>',
    "9": '<p><strong>עֵץ הַחַיִּים</strong> (<em>ʿēṣ haḥayyîm</em>) — "the tree of life." Life is a gift mediated through this tree; access to it sustains ongoing life (3:22 confirms that eating from it would grant immortality). The tree recurs in Proverbs (3:18; 11:30; 13:12; 15:4) as a wisdom metaphor, and in Revelation (2:7; 22:2, 14, 19) as the restored eschatological gift. The loss of access to the tree of life (3:24) is the fundamental consequence of the Fall; restoration to it is the fundamental promise of the new creation.</p><p><strong>עֵץ הַדַּעַת טוֹב וָרָע</strong> (<em>ʿēṣ haddaʿat ṭôb wārāʿ</em>) — "the tree of the knowledge of good and evil." <em>Daʿat</em> is experiential knowledge — not mere information but the knowing that comes from engagement. <em>Ṭôb wārāʿ</em> (good and evil) as a merism may mean comprehensive moral knowledge, or the ability to determine for oneself what is good and evil (the usurpation of divine prerogative). The serpent\'s promise (3:5) uses exactly this phrase.</p>',
    "10": '<p>The river description establishes the garden as the source of the world\'s water supply — creation\'s life flows outward from Eden. The fourfold division of rivers from a single source is geographic-theological: Eden is the fountainhead. Ezekiel 47 and Revelation 22 both invoke the same image of a river flowing from God\'s presence to sustain creation.</p>',
    "11": '<p><strong>הַפִּישׁוֹן</strong> — the Pishon is unidentified with certainty; some locate it in Arabia (associated with gold and bdellium). The detail of Havilah\'s gold (<em>zāhāb</em>) is the only other geographic anchor. The geographic specificity grounds the narrative in real geography without allowing exact modern identification — intentional or simply reflecting ancient knowledge the author assumed.</p>',
    "12": '<p><strong>בְּדֹלַח</strong> (<em>bĕḏōlaḥ</em>) — "bdellium," an aromatic resin (cf. Num 11:7 where manna is compared to it). <strong>שֹׁהַם</strong> (<em>šōham</em>) — "onyx" or "carnelian" (the exact stone is debated); it appears on the high priest\'s ephod (Exod 28:9, 20). The precious materials of the land around Eden foreshadow the materials used in the tabernacle and temple — Eden as the original sanctuary, the temple as Eden-recreation.</p>',
    "13": '<p>The Gihon is the name of the spring of Jerusalem (1 Kgs 1:33, 38, 45), associated with the city of David. Whether the Genesis Gihon is the same location or a symbolic naming, the connection links Eden\'s water-source with Jerusalem\'s central spring — the city of God as the restored Eden-center of creation.</p>',
    "14": '<p><strong>חִדֶּקֶל</strong> (<em>ḥiddeqel</em>) — the Tigris, consistently identified (Dan 10:4; Assyrian <em>Idiqlat</em>). <strong>פְּרָת</strong> (<em>pĕrāt</em>) — the Euphrates. Two of the four rivers are the great rivers of Mesopotamia — the historical-geographic frame of ANE civilization. The Eden narrative is set in recoverable geography even if the garden itself is inaccessible (3:24). The two known rivers anchor the narrative in history.</p>',
    "15": '<p><strong>לְעָבְדָהּ וּלְשָׁמְרָהּ</strong> (<em>lĕʿāḇdāh ûlĕšāmĕrāh</em>) — "to work it and to keep/guard it." <em>ʿĀḇaḏ</em> is the word for service, work, and also worship (<em>ʿăbōḏāh</em> = service/liturgy); <em>šāmar</em> is to guard, keep, watch (used of keeping commandments and keeping the sanctuary). Both terms are used together for the Levitical service of the tabernacle (Num 3:7-8; 8:26; 18:5-6). The man is placed in the garden as a priest-king: his mandate is both cultivation and guardianship, both priestly service and royal oversight.</p>',
    "16": '<p><strong>כֹּל עֵץ הַגָּן אָכֹל תֹּאכֵל</strong> (<em>kōl ʿēṣ haggan ʾākōl tōʾkēl</em>) — the permission is stated with the emphatic infinitive absolute + finite verb (<em>ʾākōl tōʾkēl</em>) — "you may freely eat." The scope of freedom is maximized before the limit is stated. The command in v. 17 comes as restriction within a broadly generous gift, not as a primary prohibition.</p>',
    "17": '<p><strong>מוֹת תָּמוּת</strong> (<em>môt tāmût</em>) — infinitive absolute + finite verb: "you will certainly die" or "dying you will die." The emphatic construction underscores the certainty and totality of the consequence. The serpent\'s counter (<em>lōʾ mōt tĕmutûn</em>, 3:4) uses the same construction negated — the debate is over the certainty of this very phrase. The death threatened may encompass separation from God, expulsion from the garden, spiritual death, and eventual physical death — all of which follow in ch 3. That the man does not physically die immediately (he lives to 930 years, 5:5) has suggested to many interpreters that the death is first relational/spiritual, with physical death as the ultimate expression.</p>',
    "18": '<p><strong>לֹא-טוֹב</strong> (<em>lōʾ-ṭôb</em>) — "it is not good." The first <em>lōʾ-ṭôb</em> in the creation narrative — the sevenfold good of ch 1 is here interrupted for the first time. The deficit is not in creation itself but in the incompleteness of the human situation: alone, without a corresponding partner.</p><p><strong>עֵזֶר כְּנֶגְדּוֹ</strong> (<em>ʿēzer kĕneḡdô</em>) — "a helper corresponding to him" or "a helper as his counterpart." <em>ʿĒzer</em> (helper) is used of God himself as helper to Israel (Ps 121:2; 124:8; Exod 18:4) — the word carries no connotation of inferiority; it describes the role of the one whose strength supplies what is lacking in the other. <em>Kĕneḡdô</em> means "as before him," "face-to-face," "his match" — the preposition <em>negeḏ</em> indicates correspondence and facing, not subordination. The woman is the man\'s equal counterpart who faces him, not an assistant beneath him.</p>',
    "19": '<p>The Qal perfect <em>yāṣar</em> ("had formed") here is likely a pluperfect — the animals had already been formed; now they are brought to the man. The narrative interest is not the sequence of creation but the human act of naming. God brings the animals to the man to see "what he would call them" (<em>mah-yiqrāʾ-lô</em>) — God observes with interest the man\'s exercise of dominion through naming.</p>',
    "20": '<p>The man names all the animals — exercising the image-bearing dominion of 1:26-28 in the most concrete form. <strong>וּלְאָדָם לֹא מָצָא</strong> (<em>ûlĕʾāḏām lōʾ māṣāʾ</em>) — "but for the man no helper corresponding to him was found." The naming of animals establishes by negative evidence the uniqueness of humanity\'s need: no animal corresponds to the man. This sets up the creation of woman not as an afterthought but as the necessary completion that the animal parade has demonstrated to be missing.</p>',
    "21": '<p><strong>תַּרְדֵּמָה</strong> (<em>tarḏēmāh</em>) — "deep sleep." The same word is used of Abraham\'s deep sleep during the covenant ceremony (15:12) and of Saul\'s sleep in the camp (1 Sam 26:12). It is a special, often divinely-induced sleep that accompanies supernatural divine action. The man is passive and unconscious while God acts — the woman\'s creation is entirely God\'s work.</p><p><strong>אַחַת מִצַּלְעֹתָיו</strong> (<em>ʾaḥat miṣṣalʿōtāyw</em>) — "one of his ribs/sides." <em>Ṣēlāʿ</em> is used elsewhere for the side of the ark (Exod 25:12; 37:3) and the side chamber of the temple (1 Kgs 6:34; Ezek 41:5-11). It can mean "rib" (the narrow sense) or "side" (the broader construction sense). Some interpreters read "side" here — God takes one side of the man to form the woman, resulting in two beings from one original. The MKT\'s "rib" follows the standard English tradition.</p>',
    "22": '<p><strong>וַיִּבֶן יְהוָה אֱלֹהִים אֶת-הַצֵּלָע</strong> (<em>wayyiḇen YHWH ʾĕlōhîm ʾet-haṣṣēlāʿ</em>) — "and the LORD God built/fashioned the rib." The verb <em>bānāh</em> (build) is used here rather than <em>yāṣar</em> (form/shape) or <em>bārāʾ</em> (create). <em>Bānāh</em> is the builder\'s verb — used of building houses, cities, walls, and the temple. Woman is built/constructed, not merely shaped. The result is then brought (<em>wayyĕbīʾehā</em>) to the man — God as the one who presents the bride, a motif with a long trajectory.</p>',
    "23": '<p><strong>זֹאת הַפַּעַם</strong> (<em>zōʾt happaʿam</em>) — "this at last" or "this one, now!" The phrase is exclamatory and immediate — Adam\'s first recorded speech is a recognition and celebration. <strong>עֶצֶם מֵעֲצָמַי וּבָשָׂר מִבְּשָׂרִי</strong> — "bone of my bones and flesh of my flesh" — a covenant kinship formula (used in 2 Sam 5:1; 19:12-13 for tribal solidarity). The man recognizes the woman as belonging to him in the deepest way — not possessively but kinship-relationally.</p><p><strong>לְזֹאת יִקָּרֵא אִשָּׁה כִּי מֵאִישׁ לֻקֳחָה זֹּאת</strong> — the <em>ʾîš/ʾiššāh</em> wordplay is explicit: "she shall be called <em>ʾiššāh</em> (woman) because from <em>ʾîš</em> (man) she was taken." The Hebrew pun is the man\'s own discovery — the naming arises from recognition of origin and correspondence. English "woman/man" or "she-man/man" approximates the wordplay; no translation fully preserves it.</p>',
    "24": '<p><strong>עַל-כֵּן</strong> (<em>ʿal-kēn</em>) — "therefore" — the narrator\'s (or God\'s) etiological comment grounding the marriage bond in the creation event. This is not the man\'s speech but the author\'s application. The verse explains a present practice by appeal to the original creation — a theological grounding of marriage in the protological order.</p><p><strong>וְדָבַק</strong> (<em>wĕḏāḇaq</em>) — "shall cleave/be joined to." <em>Dāḇaq</em> is a strong attachment word — used of clinging in loyalty (Ruth 1:14; 2:8, 21, 23), of Israel cleaving to the LORD (Deut 10:20; 11:22; 13:4; Josh 22:5; 23:8). The same intensity of covenant attachment that Israel is to have with YHWH is what a man is to have with his wife. Paul in Eph 5:31-32 will call this mystery a reference to Christ and the church.</p><p><strong>לְבָשָׂר אֶחָד</strong> (<em>lĕḇāśār ʾeḥāḏ</em>) — "one flesh." <em>Bāśār</em> encompasses the whole person in bodily existence — not merely sexual union but covenant identification, shared life, corporate personhood. "One flesh" is not primarily about sexual intercourse (though it includes it) but about the covenantal oneness of two persons.</p>',
    "25": '<p><strong>עֲרוּמִּים</strong> (<em>ʿărûmmîm</em>) — "naked." The word sets up the deliberate wordplay with the serpent\'s <em>ʿārûm</em> (crafty/shrewd, 3:1) — both words share the same consonantal root in Hebrew. The man and woman are <em>ʿārûmmîm</em> (naked, without concealment) while the serpent is <em>ʿārûm</em> (crafty, without revealing his intent). The innocence of nakedness without shame is the condition the serpent\'s craftiness will undo.</p><p><strong>וְלֹא יִתְבֹּשָׁשׁוּ</strong> (<em>wĕlōʾ yitbōšāšû</em>) — "and they were not ashamed." The verb <em>bûš</em> (ashamed, put to shame) denotes the social experience of being exposed and found deficient. Their nakedness produced no shame because there was no covering needed — no moral deficit, no rupture in relationship to God or each other. The contrast with 3:7-10 (shame, hiding, covering) makes the transition from innocence to guilt viscerally apparent.</p>'
  },
  "3": {
    "1": '<p><strong>עָרוּם</strong> (<em>ʿārûm</em>) — "shrewd/crafty." The same adjective used positively in Proverbs (12:16, 23; 13:16; 14:8, 15, 18; 22:3; 27:12) for prudent wisdom — here it is the craft that circumvents rather than serves wisdom. The deliberate wordplay with 2:25 (<em>ʿărûmmîm</em>, naked) is a literary signal: the shrewdness of the serpent exploits the openness/nakedness of the human pair.</p><p><strong>אַף כִּי-אָמַר אֱלֹהִים</strong> — "Did God really say...?" The serpent\'s opening is not a direct denial but a question that introduces doubt about the scope of the command. Note: the serpent uses <em>ʾĕlōhîm</em> (not <em>YHWH ʾĕlōhîm</em> of ch 2-3), subtly distancing the covenant name. The question misrepresents the command — God had permitted all trees; the serpent asks whether God had prohibited all trees.</p>',
    "2": '<p>The woman correctly identifies the scope of the permission ("we may eat from the trees in the garden") but her response already engages the serpent\'s framing. She corrects the misrepresentation but will in v. 3 add to the prohibition — "you must not touch it" — a slight expansion of the original command (2:17 mentions only eating, not touching). Whether this is her memory, her interpretation, or her own addition, it begins the process of misrepresenting the divine word.</p>',
    "3": '<p><strong>לֹא תֹאכְלוּ מִמֶּנּוּ וְלֹא תִגְּעוּ בּוֹ</strong> — "you must not eat from it, and you must not touch it." The addition of "touch" (<em>nāgaʿ</em>) is the woman\'s addition to the original command (2:17). The prohibition of touching as well as eating represents either a traditional fence around the law (expanding the prohibition to prevent accidental violation), a memory error, or a deliberate elaboration. In any case, the text does not present it as God\'s word — and the serpent will shortly deny the truth of the word as the woman has stated it.</p>',
    "4": '<p><strong>לֹא-מוֹת תְּמֻתוּן</strong> (<em>lōʾ-môt tĕmutûn</em>) — "you will not certainly die." The serpent uses the same emphatic construction God used in 2:17 (<em>môt tāmût</em>) but negated. It is a direct contradiction of divine speech. The three-part structure of the temptation follows: (1) question/doubt (v. 1), (2) direct denial (v. 4), (3) alternative appeal to self-interest (v. 5).</p>',
    "5": '<p><strong>כֵּאלֹהִים יֹדְעֵי טוֹב וָרָע</strong> (<em>kēʾlōhîm yōḏĕʿê ṭôb wārāʿ</em>) — "like God [or: like gods], knowing good and evil." <em>ʾĔlōhîm</em> is grammatically ambiguous — it could be "like God" (singular referent) or "like the divine beings/gods" (plural). The serpent\'s claim is that eating will elevate the humans to divine-level autonomous knowledge. The irony: after the Fall, God himself says "the man has become like one of us, knowing good and evil" (3:22) — the serpent\'s claim is partially confirmed but the cost and mode were not disclosed.</p>',
    "6": '<p><strong>כִּי טוֹב הָעֵץ לְמַאֲכָל וְכִי תַאֲוָה-הוּא לָעֵינַיִם</strong> — the threefold evaluation mirrors but corrupts the creation evaluations. The woman sees (1) good for food (<em>ṭôb lĕmaʾăkāl</em>), (2) desirable to the eye (<em>taʾăwāh hûʾ lāʿênāyim</em>), (3) desirable for gaining wisdom (<em>neḥmāḏ hāʿēṣ lĕhaśkîl</em>). The three appeals correspond to what 1 John 2:16 calls "the desire of the flesh, the desire of the eyes, and the pride of life." <em>Taʾăwāh</em> (desire, craving) is the same word used of the Israelites\' craving in the wilderness (Num 11:4; Ps 106:14).</p><p><strong>וַתִּתֵּן גַּם-לְאִישָׁהּ עִמָּהּ וַיֹּאכַל</strong> — "and she also gave some to her husband who was with her (<em>ʿimmāh</em>), and he ate." The final phrase is shocking in its brevity: he was with her. Adam was present; he does not argue, question, or resist. His sin is not deception but passive acquiescence — which Paul distinguishes (1 Tim 2:14: "Adam was not deceived, but the woman was deceived and became a transgressor").</p>',
    "7": '<p><strong>וַתִּפָּקַחְנָה עֵינֵי שְׁנֵיהֶם</strong> (<em>wattippāqaḥnāh ʿênê šĕnêhem</em>) — "and the eyes of both of them were opened." The verb <em>pāqaḥ</em> (to open eyes, to have sight restored) is used of Hagar\'s eyes being opened to see a well (21:19), of Elisha\'s prayer that Gehazi\'s eyes be opened (2 Kgs 6:17), of the blind receiving sight. The irony is that the eyes opened to knowledge that shamed rather than illuminated — they see themselves for the first time as exposed and deficient.</p><p><strong>וַיֵּדְעוּ כִּי עֵירֻמִּם הֵם</strong> (<em>wayyēdĕʿû kî ʿêrummim hēm</em>) — "and they knew that they were naked." The first thing the newly awakened moral knowledge produces is not wisdom but shame. <em>ʿEirummim</em> is a variant spelling of 2:25\'s <em>ʿărûmmîm</em> — the connection is deliberate. They were naked before and unashamed; now they are naked and ashamed. The knowledge they gained is first of their own inadequacy before God.</p>',
    "8": '<p><strong>אֶת-קוֹל יְהוָה אֱלֹהִים מִתְהַלֵּךְ בַּגָּן לְרוּחַ הַיּוֹם</strong> — "the sound/voice of the LORD God walking in the garden in the cool of the day." <em>Qôl</em> is "voice" or "sound" — the humans hide from the approaching <em>qôl</em> of God, not necessarily a visible form. <em>Lĕrûaḥ hayyôm</em> — "in the cool of the day" — literally "in the wind/spirit of the day," the late afternoon breeze. The walking suggests a regular pattern: God\'s presence in the garden was not unusual. Hiding was.</p>',
    "9": '<p><strong>אַיֶּכָּה</strong> (<em>ʾayyekāh</em>) — "Where are you?" The rhetorical question is not informational — God knows. It is an invitation to confess, to come out, to be found. The same form appears in Lam 1:1\'s "Alas!" (<em>ʾêkāh</em>) over desolated Jerusalem — a connection the rabbis made explicitly. God\'s "Where are you?" to Adam is echoed in the lament over fallen Israel. The question opens the judicial process that follows.</p>',
    "10": '<p><strong>אֶת-קֹלְךָ שָׁמַעְתִּי בַּגָּן וָאִירָא</strong> — "I heard your voice in the garden and I was afraid." The first instance of fear in Genesis — and of humans fearing God. Before the Fall, God walked in the garden and the humans were unashamed; now the same divine presence produces fear. The disruption of the relationship is total: shame toward each other (v. 7), fear toward God (v. 10). Fear of God will later become a virtue in Israel (the fear of the LORD is the beginning of wisdom, Prov 9:10) — but this first fear is guilt-driven hiding, not reverent awe.</p>',
    "11": '<p>God\'s interrogation moves from location ("Where are you?") to action ("Who told you... Have you eaten...?"). The questions are forensic — establishing facts in the manner of a judicial proceeding. The Hebrew word order in "Have you eaten from the tree from which I commanded you not to eat?" puts the tree first for emphasis: the tree was the prohibited object; eating from it is the charge.</p>',
    "12": '<p><strong>הָאִשָּׁה אֲשֶׁר נָתַתָּה עִמָּדִי</strong> — "The woman whom you gave to be with me." Adam\'s response implicates both the woman and God: <em>you gave</em> points upward, <em>she gave me</em> points sideways. The man who identified the woman as "bone of my bones" (2:23) now distances himself from her with a relative clause. The relational solidarity of 2:23-24 is instantly fractured. The syntax is revealing: "the woman — whom you gave — she gave me" — the blame-chain is grammatically stacked.</p>',
    "13": '<p><strong>הַנָּחָשׁ הִשִּׁיאַנִי</strong> (<em>hannāḥāš hiššîʾanî</em>) — "the serpent deceived me." <em>Nāšāʾ</em> (Hiphil) means to lead astray, deceive. The woman does not deny the act but names the deceiver. Paul distinguishes Eve\'s deception from Adam\'s choice (2 Cor 11:3; 1 Tim 2:14) — both sinned, but by different mechanisms. The woman\'s response is more honest than the man\'s (she confesses "and I ate" directly); the man\'s response contained no explicit confession of eating.</p>',
    "14": '<p><strong>כִּי עָשִׂיתָ זֹּאת</strong> — "because you did this." The serpent\'s curse is unconditional — no interrogation, no opportunity to respond. The serpent\'s curse has two parts: (1) lowest among animals, crawling and eating dust; (2) enmity with the woman. The crawling on its belly is a cursed abasement — whatever the serpent\'s original form, it is now permanently lowered. The dust-eating is likely a metaphor for utter defeat (Ps 72:9; Isa 49:23; Mic 7:17) rather than literal dietary prescription.</p>',
    "15": '<p><strong>אֵיבָה</strong> (<em>ʾêḇāh</em>) — "enmity/hostility." The word describes the deepest kind of irreconcilable antagonism — not mere disagreement but mortal hostility. God himself puts (<em>ʾāšît</em>, first person singular imperfect) this enmity between the serpent and the woman. The conflict is divinely ordained, not a natural consequence of the Fall alone.</p><p><strong>זַרְעֲךָ... זַרְעָהּ</strong> — "your seed... her seed." <em>Zeraʿ</em> (seed/offspring) is a collective singular — it can refer to the ongoing line of a person\'s descendants or to a specific individual within that line. The grammar does not force either interpretation. The singular pronoun <strong>הוּא</strong> (<em>hûʾ</em>, "he") in the next clause — "he will crush your head" — introduces a masculine singular referent, which some read as an individual (the messianic reading; cf. LXX <em>autos</em>, "he") and others read as a collective "it" (offspring as a group). Both readings are grammatically valid; the Christological reading is canonical reading from the vantage point of the completed Scripture.</p><p><strong>יְשׁוּפְךָ רֹאשׁ וְאַתָּה תְּשׁוּפֶנּוּ עָקֵב</strong> — the same verb <em>šûp</em> is used for both "crush" (head) and "strike" (heel). Both sides of the enmity use identical force; the asymmetry is in the body part struck — head versus heel. A crushed head is mortal; a struck heel is painful but not fatal. The resolution of the conflict is anticipated in the asymmetry: the seed of the woman delivers a fatal blow; the serpent delivers a wound.</p>',
    "16": '<p><strong>הַרְבָּה אַרְבֶּה עִצְּבוֹנֵךְ וְהֵרֹנֵךְ</strong> — "I will greatly increase your pain in childbearing." The emphatic infinitive absolute construction (<em>harbāh ʾarbbeh</em>, doubling the verbal root) stresses the intensification. <em>ʿIṣṣābôn</em> (pain/toil) is the same word used of the man\'s agricultural toil in v. 17 — both curses are expressed in the same vocabulary, suggesting a structural parallel between the woman\'s domain (childbearing) and the man\'s (ground-working), both now marked by painful labor.</p><p><strong>וְאֶל-אִישֵׁךְ תְּשׁוּקָתֵךְ וְהוּא יִמְשָׁל-בָּךְ</strong> — "your desire (<em>tĕšûqāh</em>) will be for your husband, and he will rule (<em>māšal</em>) over you." <em>Tĕšûqāh</em> (desire/longing) appears three times in the OT: here, in Song of Songs 7:10 (the husband\'s desire for the wife — reciprocal), and Gen 4:7 (sin\'s desire to control Cain — context is mastery/control). The word\'s connotation in 4:7 has led some to interpret the woman\'s desire here as a desire to control or dominate, with the man\'s ruling as the counteracting consequence. Others read it as a positive longing rendered unequal by the man\'s rule. Either way, the ordered partnership of 2:18-24 is now marked by tension and asymmetry — a description of the fallen state, not a prescription for the ideal order.</p>',
    "17": '<p><strong>אֲרוּרָה הָאֲדָמָה בַּעֲבוּרֶךָ</strong> (<em>ʾărûrāh hāʾăḏāmāh baʿăḇûrekā</em>) — "cursed is the ground because of you." Note: the man is not cursed directly (as the serpent was, v. 14) but the <em>ʾăḏāmāh</em> (ground) is cursed because of him. The wordplay between <em>ʾāḏām</em> (man) and <em>ʾăḏāmāh</em> (ground) — established at 2:7 — now carries its full weight: the man is locked in a cursed relationship with the very source from which he was formed. <em>ʿIṣṣābôn</em> (toil/pain) — the same word as the woman\'s pain in v. 16: both curses produce <em>ʿiṣṣābôn</em>, labor transformed into painful striving.</p>',
    "18": '<p><strong>קוֹץ וְדַרְדַּר</strong> (<em>qôṣ wĕdardar</em>) — "thorns and thistles." The earth produces what opposes cultivation rather than facilitating it. The same pairing appears in Hos 10:8 as an image of divine judgment. The thorn/thistle combination signals that the ground is no longer a willing partner in the man\'s vocation — it resists, frustrates, and competes with the cultivated crop.</p>',
    "19": '<p><strong>בְּזֵעַת אַפֶּיךָ תֹּאכַל לֶחֶם</strong> (<em>bĕzēʿat ʾappêkā tōʾkal leḥem</em>) — "by the sweat of your face you will eat bread." The preposition phrase establishes the new mode: by painful exertion, not the easy abundance of Eden. <strong>עַד שׁוּבְךָ אֶל-הָאֲדָמָה כִּי מִמֶּנָּה לֻקָּחְתָּ</strong> — "until you return to the ground, for from it you were taken." The Pual perfect <em>luqqāḥtā</em> (you were taken) connects back to 2:7 and 2:23 — the same verb describes the rib taken from Adam to make Eve. Now the man is taken from the ground and will be returned to it. <strong>כִּי-עָפָר אַתָּה וְאֶל-עָפָר תָּשׁוּב</strong> — "for dust you are, and to dust you shall return." The inclusio with 2:7 (<em>ʿāpār min-hāʾăḏāmāh</em>) frames the human story: dust-sourced, dust-destined.</p>',
    "20": '<p><strong>חַוָּה</strong> (<em>ḥawwāh</em>) — "Eve." The name is connected to <em>ḥay</em> (living) — she is "the mother of all living" (<em>ʾēm kol-ḥāy</em>). The naming of his wife after the curse is itself a statement of faith: in the moment of the death-sentence, the man names the woman "Life-giver." The act anticipates the <em>zeraʿ</em> promise of v. 15 — through the woman, life will continue and the promised offspring will come.</p>',
    "21": '<p><strong>כָּתְנוֹת עוֹר</strong> (<em>kotnôt ʿôr</em>) — "garments of skin." God himself clothes the human pair — the first act of divine provision after judgment. The skin garments require the death of an animal; whether this implies sacrifice is implied but not stated. The contrast with the fig-leaf coverings (<em>ḥăgorāh</em>, 3:7) is significant: human covering is insufficient and temporary; divine covering is permanent and adequate. The theological tradition reads this as the first atonement-picture.</p>',
    "22": '<p><strong>הֵן הָאָדָם הָיָה כְּאַחַד מִמֶּנּוּ לָדַעַת טוֹב וָרָע</strong> — "Behold, the man has become like one of us, knowing good and evil." The serpent\'s promise (3:5) was not entirely false — the knowledge was gained. But what the serpent concealed was the cost and the mode: knowledge through disobedience, not through maturation under God\'s guidance. The divine "us" recurs (as in 1:26) — still unexplained in the text itself.</p><p><strong>וְעַתָּה פֶּן-יִשְׁלַח יָדוֹ</strong> — "and now, lest he reach out his hand." The concern is not that immortality would be too good for the fallen human but that immortality in the condition of moral ruin would be unremitting misery — a fallen being locked into endless life. The expulsion from Eden is thus an act of mercy as well as judgment: the way to the tree of life is blocked until the condition that makes the tree deadly can be reversed.</p>',
    "23": '<p><strong>וַיְשַׁלְּחֵהוּ יְהוָה אֱלֹהִים מִגַּן-עֵדֶן</strong> (<em>wayĕšallĕḥēhû YHWH ʾĕlōhîm miggan-ʿēḏen</em>) — "and the LORD God sent him out from the Garden of Eden." <em>Šāllaḥ</em> (Piel, intensive) means to send out forcefully — used of divorce (Deut 24:1-3) and of expulsion. The same verb will appear when Abraham sends out Hagar (21:14) and when the Egyptians expel Israel (Exod 12:33). The divine expulsion is an irrevocable change of status.</p>',
    "24": '<p><strong>אֶת-הַכְּרֻבִים</strong> (<em>ʾet-hakkĕrubîm</em>) — "the cherubim." The cherubim appear here for the first time — divine guardians who prevent unauthorized access to the holy. They will appear as the guardians of the ark of the covenant (Exod 25:18-22; 37:7-9), woven into the tabernacle curtains (Exod 26:1), carved into Solomon\'s temple (1 Kgs 6:23-29), and in Ezekiel\'s throne-chariot visions (Ezek 1:5-25; 10). They are the guardians of the divine throne and presence; here they guard the tree of life.</p><p><strong>אֵת לַהַט הַחֶרֶב הַמִּתְהַפֶּכֶת</strong> (<em>ʾêt lahaṭ haḥereḇ hammithappe|ket</em>) — "the flaming/turning sword." <em>Lahaṭ</em> (flame) + the Hitpael participle of <em>hāpak</em> (to turn, overturn) — the sword turns in every direction, covering every angle of approach. The garden is sealed: the cherubim guard the eastern entrance, the sword covers all other approaches. The way back to Eden is completely blocked — until Revelation 22 shows the tree of life in the New Jerusalem, accessible again.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    merge_comm(existing, GENESIS)
    save_comm('mkt-original', 'genesis', existing)
    print('Genesis 1-3 mkt-original written.')

if __name__ == '__main__':
    main()
